  it("should call the function when a string-keyed rule has a function value", () => {
    plural.addRule("uniquetestword123", (w: string) => w.toUpperCase() + "_PLURAL");

    const result = plural("uniquetestword123");

    expect(result).toBe("UNIQUETESTWORD123_PLURAL");
  });
